const config = $('Execute LoadMappings').first().json;
const processedLogins = $('Get Processed Agents')
  .all()
  .map((item) => item.json.agent_login)
  .filter(Boolean);

return [
  {
    json: {
      ...config,
      processed_agents: processedLogins,
      processed_agents_count: processedLogins.length,
    },
  },
];

const ctx = $('Continue Phase 2').first().json;
const fteGroups = ctx.mappings?.fte_groups || [];
const newsSkills = ctx.mappings?.news_exception_skills || [];

const skills = [
  ...new Set([
    ...fteGroups.map((row) => row.skill_name),
    ...newsSkills.map((row) => row.skill_name),
  ]),
].filter(Boolean);

if (skills.length === 0) {
  throw new Error('System Error: support skills list is empty (mappings/fte_groups.json)');
}

return skills.map((skill_name) => ({ json: { skill_name } }));

const processed = new Set(
  $('Continue Phase 2').first().json.processed_agents || [],
);

return $input
  .all()
  .filter((item) => item.json.agent_login && !processed.has(item.json.agent_login))
  .map((item) => ({ json: item.json }));

// ТЗ §4.5 шаг 8: тип контейнера (mappings/container.json / 9hrs / 12hrs)
// BE2 если не распознан
return $input.all();
